		/// |--------------------------------------|<br/>
		/// | ma_thread_priority_idle              |<br/>
		/// | ma_thread_priority_lowest            |<br/>
		/// | ma_thread_priority_low               |<br/>
		/// | ma_thread_priority_normal            |<br/>
		/// | ma_thread_priority_high              |<br/>
		/// | ma_thread_priority_highest (default) |<br/>
		/// | ma_thread_priority_realtime          |<br/>
		/// | ma_thread_priority_default           |<br/>
		/// |--------------------------------------|<br/>
		/// threadStackSize<br/>
		/// The desired size of the stack for the audio thread. Defaults to the operating system's default.<br/>
		/// pUserData<br/>
		/// A pointer to application-defined data. This can be accessed from the context object directly such as `context.pUserData`.<br/>
		/// allocationCallbacks<br/>
		/// Structure containing custom allocation callbacks. Leaving this at defaults will cause it to use MA_MALLOC, MA_REALLOC and MA_FREE. These allocation<br/>
		/// callbacks will be used for anything tied to the context, including devices.<br/>
