		/// ALSA will typically enumerate many different devices which can be intrusive and not user-friendly. To combat this, miniaudio will enumerate only unique<br/>
		/// card/device pairs by default. The problem with this is that you lose a bit of flexibility and control. Setting alsa.useVerboseDeviceEnumeration makes<br/>
		/// it so the ALSA backend includes all devices. Defaults to false.<br/>
		/// pulse.pApplicationName<br/>
		/// PulseAudio only. The application name to use when initializing the PulseAudio context with `pa_context_new()`.<br/>
		/// pulse.pServerName<br/>
		/// PulseAudio only. The name of the server to connect to with `pa_context_connect()`.<br/>
		/// pulse.tryAutoSpawn<br/>
		/// PulseAudio only. Whether or not to try automatically starting the PulseAudio daemon. Defaults to false. If you set this to true, keep in mind that<br/>
		/// miniaudio uses a trial and error method to find the most appropriate backend, and this will result in the PulseAudio daemon starting which may be<br/>
		/// intrusive for the end user.<br/>
		/// coreaudio.sessionCategory<br/>
		/// iOS only. The session category to use for the shared AudioSession instance. Below is a list of allowable values and their Core Audio equivalents.<br/>
		/// |-----------------------------------------|-------------------------------------|<br/>
		/// | miniaudio Token                         | Core Audio Token                    |<br/>
		/// |-----------------------------------------|-------------------------------------|<br/>
		/// | ma_ios_session_category_ambient         | AVAudioSessionCategoryAmbient       |<br/>
		/// | ma_ios_session_category_solo_ambient    | AVAudioSessionCategorySoloAmbient   |<br/>
		/// | ma_ios_session_category_playback        | AVAudioSessionCategoryPlayback      |<br/>
		/// | ma_ios_session_category_record          | AVAudioSessionCategoryRecord        |<br/>
		/// | ma_ios_session_category_play_and_record | AVAudioSessionCategoryPlayAndRecord |<br/>
		/// | ma_ios_session_category_multi_route     | AVAudioSessionCategoryMultiRoute    |<br/>
		/// | ma_ios_session_category_none            | AVAudioSessionCategoryAmbient       |<br/>
		/// | ma_ios_session_category_default         | AVAudioSessionCategoryAmbient       |<br/>
		/// |-----------------------------------------|-------------------------------------|<br/>
		/// coreaudio.sessionCategoryOptions<br/>
		/// iOS only. Session category options to use with the shared AudioSession instance. Below is a list of allowable values and their Core Audio equivalents.<br/>
		/// |---------------------------------------------------------------------------|------------------------------------------------------------------|<br/>
		/// | miniaudio Token                                                           | Core Audio Token                                                 |<br/>
		/// |---------------------------------------------------------------------------|------------------------------------------------------------------|<br/>
		/// | ma_ios_session_category_option_mix_with_others                            | AVAudioSessionCategoryOptionMixWithOthers                        |<br/>
		/// | ma_ios_session_category_option_duck_others                                | AVAudioSessionCategoryOptionDuckOthers                           |<br/>
		/// | ma_ios_session_category_option_allow_bluetooth                            | AVAudioSessionCategoryOptionAllowBluetooth                       |<br/>
		/// | ma_ios_session_category_option_default_to_speaker                         | AVAudioSessionCategoryOptionDefaultToSpeaker                     |<br/>
		/// | ma_ios_session_category_option_interrupt_spoken_audio_and_mix_with_others | AVAudioSessionCategoryOptionInterruptSpokenAudioAndMixWithOthers |<br/>
		/// | ma_ios_session_category_option_allow_bluetooth_a2dp                       | AVAudioSessionCategoryOptionAllowBluetoothA2DP                   |<br/>
		/// | ma_ios_session_category_option_allow_air_play                             | AVAudioSessionCategoryOptionAllowAirPlay                         |<br/>
		/// |---------------------------------------------------------------------------|------------------------------------------------------------------|<br/>
		/// coreaudio.noAudioSessionActivate<br/>
		/// iOS only. When set to true, does not perform an explicit [[AVAudioSession sharedInstace] setActive:true] on initialization.<br/>
		/// coreaudio.noAudioSessionDeactivate<br/>
		/// iOS only. When set to true, does not perform an explicit [[AVAudioSession sharedInstace] setActive:false] on uninitialization.<br/>
		/// jack.pClientName<br/>
		/// The name of the client to pass to `jack_client_open()`.<br/>
		/// jack.tryStartServer<br/>
		/// Whether or not to try auto-starting the JACK server. Defaults to false.<br/>
		/// It is recommended that only a single context is active at any given time because it's a bulky data structure which performs run-time linking for the<br/>
		/// relevant backends every time it's initialized.<br/>
		/// The location of the context cannot change throughout it's lifetime. Consider allocating the `ma_context` object with `malloc()` if this is an issue. The<br/>
		/// reason for this is that a pointer to the context is stored in the `ma_device` structure.<br/>
		/// Example 1 - Default Initialization<br/>
		/// ----------------------------------<br/>
		/// The example below shows how to initialize the context using the default configuration.<br/>
		/// ```c<br/>
		/// ma_context context;<br/>
		/// ma_result result = ma_context_init(NULL, 0, NULL, <br/>
		/// &context<br/>
		/// );<br/>
		/// if (result != MA_SUCCESS) {<br/>
		/// // Error.<br/>
		/// }<br/>
		/// ```<br/>
		/// Example 2 - Custom Configuration<br/>
		/// --------------------------------<br/>
		/// The example below shows how to initialize the context using custom backend priorities and a custom configuration. In this hypothetical example, the program<br/>
		/// wants to prioritize ALSA over PulseAudio on Linux. They also want to avoid using the WinMM backend on Windows because it's latency is too high. They also<br/>
		/// want an error to be returned if no valid backend is available which they achieve by excluding the Null backend.<br/>
		/// For the configuration, the program wants to capture any log messages so they can, for example, route it to a log file and user interface.<br/>
		/// ```c<br/>
		/// ma_backend backends[] = {<br/>
		/// ma_backend_alsa,<br/>
		/// ma_backend_pulseaudio,<br/>
		/// ma_backend_wasapi,<br/>
		/// ma_backend_dsound<br/>
		/// };<br/>
		/// ma_log log;<br/>
		/// ma_log_init(<br/>
		/// &log<br/>
		/// );<br/>
		/// ma_log_register_callback(<br/>
		/// &log<br/>
		/// , ma_log_callback_init(my_log_callbac, pMyLogUserData));<br/>
		/// ma_context_config config = ma_context_config_init();<br/>
		/// config.pLog = <br/>
		/// &log;<br/>
		/// // Specify a custom log object in the config so any logs that are posted from ma_context_init() are captured.<br/>
		/// ma_context context;<br/>
		/// ma_result result = ma_context_init(backends, sizeof(backends)/sizeof(backends[0]), <br/>
		/// &config<br/>
		/// , <br/>
		/// &context<br/>
		/// );<br/>
		/// if (result != MA_SUCCESS) {<br/>
		/// // Error.<br/>
		/// if (result == MA_NO_BACKEND) {<br/>
		/// // Couldn't find an appropriate backend.<br/>
		/// }<br/>
		/// }<br/>
		/// // You could also attach a log callback post-initialization:<br/>
		/// ma_log_register_callback(ma_context_get_log(<br/>
		/// &context<br/>
		/// ), ma_log_callback_init(my_log_callback, pMyLogUserData));<br/>
		/// ```<br/>
		/// See Also<br/>
		/// --------<br/>
		/// ma_context_config_init()<br/>
		/// ma_context_uninit()<br/>
		/// </summary>
		public static MaResult MaContextInit(MaBackend* backends, uint backendCount, in MaContextConfig pConfig, MaContextPtr pContext)
		{
			fixed (MaContextConfig* ppConfig = &pConfig)
			{
				MaResult ret = MaContextInitNative(backends, backendCount, (MaContextConfig*)ppConfig, (MaContext*)pContext);
				return ret;
			}
		}

